diff --git a/packages/codesandboxer/src/fetchFiles/fetchFiles.test.js b/packages/codesandboxer/src/fetchFiles/fetchFiles.test.js
new file mode 100644
index 0000000..abf7588
--- /dev/null
+++ b/packages/codesandboxer/src/fetchFiles/fetchFiles.test.js
@@ -0,0 +1,49 @@
+import fetchFiles from './index';
+import isomorphic from 'isomorphic-fetch';
+
+const BBInfo = {
+  account: 'atlassian',
+  repository: 'atlaskit-mk-2',
+  branch: '6546190ec6d8e1e47566882177fa941bcb8bf576',
+  host: 'bitbucket',
+};
+
+const getMainObj = (userOpts = {}) => ({
+  examplePath: 'packages/elements/avatar/examples/01-basicAvatar.js',
+  pkgJSON: 'packages/elements/avatar/package.json',
+  gitInfo: BBInfo,
+  importReplacements: [['packages/elements/avatar/src', '@atlaskit/avatar']],
+  dependencies: { '@atlaskit/avatar': 'latest' },
+  providedFiles: {},
+  ...userOpts,
+});
+
+it('should fetch an example from atlaskit', () => {
+  const config = {
+    examplePath: 'packages/elements/avatar/examples/01-basicAvatar.js',
+    pkgJSON: 'packages/elements/avatar/package.json',
+    gitInfo: BBInfo,
+    importReplacements: [['packages/elements/avatar/src', '@atlaskit/avatar']],
+    dependencies: { '@atlaskit/avatar': 'latest' },
+  };
+  return fetchFiles(getMainObj()).then(res => {
+    expect(res.files).toMatchSnapshot();
+  });
+});
+it('should fetch an example from react-select', () => {
+  const GHInfo = {
+    name: 'JedWatson',
+    repository: 'react-select',
+    branch: 'f95a710b9e8a7b6134dd38afcf83f05c0f09f71e',
+    host: 'github',
+  };
+
+  const config = {
+    examplePath: 'docs/home/examples/BasicSingle.js',
+    gitInfo: GHInfo,
+    dependencies: { 'react-select': 'latest' },
+  };
+  return fetchFiles(getMainObj()).then(res => {
+    expect(res.files).toMatchSnapshot();
+  });
+});

diff --git a/packages/codesandboxer/src/fetchRelativeFile/fetchRelativeFile.test.js b/packages/codesandboxer/src/fetchRelativeFile/fetchRelativeFile.test.js
new file mode 100644
index 0000000..9b2763d
--- /dev/null
+++ b/packages/codesandboxer/src/fetchRelativeFile/fetchRelativeFile.test.js
@@ -0,0 +1,85 @@
+import cases from 'jest-in-case';
+import fetchRelativeFile from './';
+import getUrl from './getUrl';
+import isomorphic from 'isomorphic-fetch';
+const GHConfig = {
+  account: 'noviny',
+  repository: 'react-codesandboxer',
+  branch: 'ca41dfb340eed67c7f755e0b03939652d1f42cc7',
+  host: 'github',
+};
+
+const BBConfig = {
+  account: 'atlassian',
+  repository: 'atlaskit-mk-2',
+  branch: '6546190ec6d8e1e47566882177fa941bcb8bf576',
+  host: 'bitbucket',
+};
+
+describe.skip('fetchRelativeFile()', () => {
+  it('should fetch a .js file in a subdirectory', async () => {
+    return fetchRelativeFile(
+      'src/CodeSandboxer/index.js',
+      {},
+      [],
+      GHConfig,
+    ).then(({ file, deps, internalImports }) => {
+      expect(deps).toMatchObject({ react: 'latest' });
+      expect(internalImports).toEqual(
+        expect.arrayContaining(['../types', '../fetchFiles']),
+      );
+      expect(file).toMatchSnapshot();
+    });
+  });
+  it('should fetch an index.js file in a named subdirectory', async () => {
+    return fetchRelativeFile('src/CodeSandboxer', {}, [], GHConfig).then(
+      ({ file, deps, internalImports }) => {
+        expect(deps).toMatchObject({ react: 'latest' });
+        expect(internalImports).toEqual(
+          expect.arrayContaining(['../types', '../fetchFiles']),
+        );
+        expect(file).toMatchSnapshot();
+      },
+    );
+  });
+  it('should fetch a .js file at the root');
+  it('should fetch a .png file in a subdirectory');
+  it('should fetch a .png file at the root');
+  it('should fetch a .json file in a subdirectory');
+  it('should fetch a .json file at the root', async () => {
+    return fetchRelativeFile('package.json', {}, [], GHConfig).then(
+      ({ file, deps, internalImports }) => {
+        expect(deps).toMatchObject({});
+        expect(internalImports).toEqual(expect.arrayContaining([]));
+        expect(file).toMatchSnapshot();
+      },
+    );
+  });
+});
+
+cases(
+  'getUrl()',
+  ({ path, expectedType }) => {
+    const { fileType, url } = getUrl(path, GHConfig);
+    expect(fileType).toBe(expectedType);
+  },
+  [
+    { name: 'js file', path: 'something.js', expectedType: '.js' },
+    { name: 'png file', path: 'something.png', expectedType: '.png' },
+    {
+      name: 'png file extended',
+      path: 'abc/something.png',
+      expectedType: '.png',
+    },
+    {
+      name: 'png file extended',
+      path: 'abc/something.json',
+      expectedType: '.json',
+    },
+    {
+      name: 'root package.json fetch',
+      path: 'package.json',
+      expectedType: '.json',
+    },
+  ],
+);

